import{c as e,Q as r,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"User Attributes","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/user-attributes.md","filePath":"guide/admin/user-attributes.md","lastUpdated":1779094756000}'),s={name:"guide/admin/user-attributes.md"};function i(n,t,d,u,l,h){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="user-attributes" tabindex="-1">User Attributes <a class="header-anchor" href="#user-attributes" aria-label="Permalink to &quot;User Attributes&quot;">​</a></h1><p>The <strong>User Attributes</strong> page defines the custom profile fields available across customers. When you add an attribute here, every customer can choose to enable it; their users then see the field on the Account page and the Complete Profile flow.</p><h2 id="list-page" tabindex="-1">List page <a class="header-anchor" href="#list-page" aria-label="Permalink to &quot;List page&quot;">​</a></h2><h3 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h3><ul><li><strong>New Attribute</strong> button (top right).</li><li><strong>Status</strong> dropdown — All / Active / Archived. Defaults to <strong>Active</strong>.</li><li>Count chip — number of attributes matching the current status.</li></ul><h3 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Label</strong></td><td>Human-readable name (e.g. &quot;Employee ID&quot;).</td></tr><tr><td><strong>Key</strong></td><td>Machine slug, lowercase with underscores. <strong>Immutable after creation.</strong></td></tr><tr><td><strong>Type</strong></td><td>Text / Number / Select / Multi-Select / Date / Switch.</td></tr><tr><td><strong>Required</strong></td><td>Yes (green) / No (muted). Default for new customers.</td></tr><tr><td><strong>Order</strong></td><td>Numeric sort order in forms.</td></tr><tr><td><strong>Status</strong></td><td>Active / Archived.</td></tr><tr><td><strong>Actions</strong></td><td>Edit (disabled for archived), Archive (active only, with confirmation).</td></tr></tbody></table><h2 id="creating-an-attribute" tabindex="-1">Creating an attribute <a class="header-anchor" href="#creating-an-attribute" aria-label="Permalink to &quot;Creating an attribute&quot;">​</a></h2><p>Click <strong>New Attribute</strong>.</p><table tabindex="0"><thead><tr><th>Field</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Key</strong></td><td>Lowercase letters, numbers, underscores. Must match <code>^[a-z][a-z0-9_]{1,63}$</code>. <strong>Cannot be changed later.</strong></td></tr><tr><td><strong>Label</strong></td><td>Required.</td></tr><tr><td><strong>Type</strong></td><td>Required. Cannot be changed after creation.</td></tr><tr><td><strong>Options</strong></td><td>Shown for Select and Multi-Select types. Chip editor — add and remove options. At least one option is required.</td></tr><tr><td><strong>Placeholder</strong></td><td>Hint text shown in the form field.</td></tr><tr><td><strong>Sort Order</strong></td><td>Number input. Auto-increments based on existing attributes.</td></tr><tr><td><strong>Required by default</strong></td><td>Toggle. Sets the default for customers who enable the attribute.</td></tr></tbody></table><p>Click <strong>Create</strong>. The attribute appears in the list as <code>active</code>.</p><h2 id="editing-an-attribute" tabindex="-1">Editing an attribute <a class="header-anchor" href="#editing-an-attribute" aria-label="Permalink to &quot;Editing an attribute&quot;">​</a></h2><p>The pencil icon opens the edit modal with the same fields as Create, but <strong>Key</strong> and <strong>Type</strong> are read-only. You can change Label, Options (for select types), Placeholder, Sort Order, and the Required-by-default toggle.</p><h2 id="archiving-an-attribute" tabindex="-1">Archiving an attribute <a class="header-anchor" href="#archiving-an-attribute" aria-label="Permalink to &quot;Archiving an attribute&quot;">​</a></h2><p>The trash icon archives the attribute. Archived attributes:</p><ul><li>Do not appear on user profile forms.</li><li>Cannot be edited.</li><li>Are hidden from the default list view.</li></ul><p>Archive is the closest thing to delete the page offers — there is no destructive delete, by design. Existing values on user profiles are preserved.</p><h2 id="how-customers-use-these-attributes" tabindex="-1">How customers use these attributes <a class="header-anchor" href="#how-customers-use-these-attributes" aria-label="Permalink to &quot;How customers use these attributes&quot;">​</a></h2><p>Each customer chooses which attributes are active for their users on the <strong>User Attributes</strong> tab of the customer detail page (operator side) or via the Customer Portal <strong>Settings → User Attributes</strong> (customer side). They can override the &quot;required&quot; default per customer.</p><p>Users see the attributes on:</p><ul><li>The <strong>Complete Profile</strong> flow during first sign-in (required ones must be filled).</li><li>Their <strong>Account</strong> page → User Attributes section (for ongoing edits).</li><li>The <strong>invite acceptance</strong> form (the relevant ones, depending on the customer&#39;s configuration).</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>The slug pattern is strict on purpose — keys appear in API payloads and webhooks.</li><li>&quot;Required by default&quot; only affects the initial setting per customer; customers can relax the requirement on their side.</li><li>The page never deletes data. Archived attributes can be revisited and listed by switching the Status filter to &quot;Archived&quot;.</li></ul>',23)])])}const b=e(s,[["render",i]]);export{g as __pageData,b as default};
